#include<bits/stdc++.h>
using namespace std;
int n;
struct Edge
{
    int u,v,w;
    bool operator<(const Edge&b)const
    {
        return w<b.w;
    }
}e[100010];
int fa[100010],siz[100010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            fa[i]=i;
            siz[i]=1;
        }
        for(int i=1;i<n;i++)
        {
            scanf("%d%d%d",&e[i].u,&e[i].v,&e[i].w);
        }
        long long ans=0;
        sort(e+1,e+n);
        for(int i=1;i<n;i++)
        {
            int a=find(e[i].u),b=find(e[i].v),w=e[i].w;
            if(a!=b)
            {
                ans+=1ll*(siz[a]*siz[b]-1)*(w+1);
                fa[a]=b;
                siz[b]+=siz[a];
            }
        }
        printf("%lld\n",ans);
    }
    return 0;
}
